// get data from database
function getData($sql)
{
    global $connection;

    // Execute the query
    $result = mysqli_query($connection, $sql);

    // Check if the query was successful
    if (!$result) {
        die("Query failed: " . mysqli_error($connection));
    }

    return $result;
}


/*****************  helper function start  *******************/
const PROJECTID = "P0005";

function GetDeliveryPointList() { $project_id = PROJECTID; $sql = "SELECT delivery_point_name,delivery_pid FROM deliverypoint WHERE project_id = '$project_id' ORDER BY delivery_point_name ASC"; $list = ''; $result = getData($sql); if (mysqli_num_rows($result) > 0) { while ($item = mysqli_fetch_object($result)) { $list .= '<option value="' . $item->delivery_pid . '">' . $item->delivery_point_name . '</option>'; } } return $list; } function GetProductList() { $project_id = PROJECTID; $sql = "SELECT product_id,product_name FROM product WHERE status = 1 AND project_id = '$project_id' ORDER BY product_name ASC"; $list = ''; $result = getData($sql); if (mysqli_num_rows($result) > 0) { while ($item = mysqli_fetch_object($result)) { $list .= '<option value="' . $item->product_id . '">' . $item->product_name . '</option>'; } } return $list; } function GetCategoryList() { $project_id = PROJECTID; $sql = "SELECT * FROM catagory WHERE project_id = '$project_id' ORDER BY catagory_name ASC"; $list = ''; $result = getData($sql); if (mysqli_num_rows($result) > 0) { while ($item = mysqli_fetch_object($result)) { $list .= '<option value="' . $item->catagory_code . '">' . $item->catagory_name . '</option>'; } } return $list; } function formatDateDMY($originalDate) { if ($originalDate == "") { return ""; } return date("Y-m-d", strtotime($originalDate)); } function ellipsisPagination($totalRecord, $block = 12, $func = "nextPage") { $callFunc = $func ?: "nextPage"; $currentPage = isset($_POST['page_no']) ? intval($_POST['page_no']) : 1; $from = isset($_POST['from']) ? intval($_POST['from']) : 0; $block = $block ?: 12; $totalPage = ceil($totalRecord / $block); $paginationStr = ""; if ($currentPage > 1) { $prevPage = $currentPage - 1; $prevFrom = ($prevPage - 1) * $block; $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc($prevFrom, $block, $prevPage)\">&laquo;</button>"; } else { $paginationStr .= "<button class='join-item btn' disabled>&laquo;</button>"; } if ($totalPage <= 7) { for ($i = 1; $i <= $totalPage; $i++) { $from = ($i - 1) * $block; $activeClass = $i == $currentPage ? " btn-active" : ""; $paginationStr .= "<button class='join-item btn$activeClass' onclick=\"$callFunc($from, $block, $i)\">$i</button>"; } } else { if ($currentPage <= 4) { for ($i = 1; $i <= 5; $i++) { $from = ($i - 1) * $block; $activeClass = $i == $currentPage ? " btn-active" : ""; $paginationStr .= "<button class='join-item btn$activeClass' onclick=\"$callFunc($from, $block, $i)\">$i</button>"; } $paginationStr .= "<span class='join-item btn'>...</span>"; $from = ($totalPage - 1) * $block; $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc($from, $block, $totalPage)\">$totalPage</button>"; } elseif ($currentPage > 4 && $currentPage < $totalPage - 3) { $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc(0, $block, 1)\">1</button>"; $paginationStr .= "<span class='join-item btn'>...</span>"; for ($i = $currentPage - 1; $i <= $currentPage + 1; $i++) { $from = ($i - 1) * $block; $activeClass = $i == $currentPage ? " btn-active" : ""; $paginationStr .= "<button class='join-item btn$activeClass' onclick=\"$callFunc($from, $block, $i)\">$i</button>"; } $paginationStr .= "<span class='join-item btn'>...</span>"; $from = ($totalPage - 1) * $block; $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc($from, $block, $totalPage)\">$totalPage</button>"; } else { $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc(0, $block, 1)\">1</button>"; $paginationStr .= "<span class='join-item btn'>...</span>"; for ($i = $totalPage - 4; $i <= $totalPage; $i++) { $from = ($i - 1) * $block; $activeClass = $i == $currentPage ? " btn-active" : ""; $paginationStr .= "<button class='join-item btn$activeClass' onclick=\"$callFunc($from, $block, $i)\">$i</button>"; } } } if ($currentPage < $totalPage) { $nextPage = $currentPage + 1; $nextFrom = ($currentPage) * $block; $paginationStr .= "<button class='join-item btn' onclick=\"$callFunc($nextFrom, $block, $nextPage)\">&raquo;</button>"; } else { $paginationStr .= "<button class='join-item btn' disabled>&raquo;</button>"; } return $paginationStr; } function getStockBalanceQty($project_id, $product_id, $store_id, $date_to) { if ($product_id == "") { return 0; } if ($date_to == "") { $date_to = date("Y-m-d"); } $sql = "SELECT (SUM(dr) - SUM(cr)) as balance_qty FROM stock_ledger WHERE product_id = '$product_id' AND create_date <= '$date_to'"; if ($project_id != "") { $sql .= " AND project_id = '$project_id'"; } if ($store_id != "") { $sql .= " AND store_id = '$store_id'"; } $result = getData($sql); if ($result && $row = mysqli_fetch_assoc($result)) { return isset($row['balance_qty']) && $row['balance_qty'] > 0 ? $row['balance_qty'] : 0; } return 0; } if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action'])) { header('Content-Type: application/json; charset=UTF-8'); if (ob_get_length()) ob_end_clean(); if ($_POST['action'] === 'get_subcategories') { $category_code = isset($_POST['category_code']) ? $_POST['category_code'] : ''; $project_id = PROJECTID; $list = '<option value="" selected>Select Sub Category</option>'; if ($category_code !== '') { $sql = "SELECT * FROM subcatagory WHERE catagory_id = '$category_code' AND project_id = '$project_id' ORDER BY subcatagory_name ASC"; $result = getData($sql); if (mysqli_num_rows($result) > 0) { while ($item = mysqli_fetch_object($result)) { $list .= '<option value="' . $item->subcatagory_id . '">' . $item->subcatagory_name . '</option>'; } } } echo json_encode(['data' => $list]); exit; } if ($_POST['action'] === 'get_product_stock') { $perPage = 100; $from = isset($_POST['from']) ? intval($_POST['from']) : 0; $to = isset($_POST['to']) ? intval($_POST['to']) : $perPage; if ($from == "") { $from = 0; } if ($to == "") { $to = $perPage; } $date_from = !empty($_POST['date_from']) ? formatDateDMY($_POST['date_from']) : ''; $date_to = !empty($_POST['date_to']) ? formatDateDMY($_POST['date_to']) : ''; $category = isset($_POST['category_id']) ? $_POST['category_id'] : ''; $subcategory = isset($_POST['subCategory_id']) ? $_POST['subCategory_id'] : ''; $delivery_point = isset($_POST['delivery_point_id']) ? $_POST['delivery_point_id'] : ''; $product = isset($_POST['product_id']) ? $_POST['product_id'] : ''; $project_id = PROJECTID; $sql = "SELECT m.delivery_point as store_id,m.project_id,p.project_name,p.location,d.delivery_point_name,s.product as productID,po.product_id,po.product_type,s.details,po.product_name,po.product_desc,po.m_unit,SUM((s.qty+s.free_qty)) as order_qty,po.unit_price,m.sales_date as sales_date,m.voucher_no as invoice, c.sub_head_name as party_name FROM sales_master AS m LEFT JOIN sales_details AS s ON m.voucher_no = s.voucher_no AND m.project_id = s.project_id LEFT JOIN product AS po ON s.product = po.product_id LEFT JOIN project AS p ON p.project_id = m.project_id LEFT JOIN deliverypoint AS d ON m.delivery_point = d.delivery_pid LEFT JOIN sub_acc_head AS c ON m.customer = c.sub_id WHERE s.delivery_qty = 0 AND m.status = 1 AND m.project_id ='$project_id'"; if ($category != "") { $sql .= " AND po.catagory = '$category'"; } if ($subcategory != "") { $sql .= " AND po.subcatagory = '$subcategory'"; } if ($delivery_point != "") { $sql .= " AND m.delivery_point = '$delivery_point'"; } if ($product != "") { $sql .= " AND s.product = '$product'"; } if ($date_from && !$date_to) { $sql .= " AND m.sales_date >= '$date_from'"; } elseif (!$date_from && $date_to) { $sql .= " AND m.sales_date <= '$date_to'"; } elseif ($date_from && $date_to) { $sql .= " AND m.sales_date BETWEEN '$date_from' AND '$date_to'"; } $sql .= " GROUP BY po.product_id"; $totalResult = getData($sql); $totalRecord = mysqli_num_rows($totalResult); $sql .= " ORDER BY po.product_name ASC LIMIT $from,$to"; $result = getData($sql); $Pagination = ''; if ($totalRecord > 0) { $Pagination = ellipsisPagination($totalRecord, $perPage, 'nextPage'); } $htmlTableHead = '<div class="text-3xl text-center">(Meghna Star CABLES & Electrical Appliances Ltd)</div> <div class="text-center"> Head Office: <span class="text-primary">Gulshan -1, Dhaka -1212, Bangladesh</span> </div>'; $stocks = []; $htmlContent = '<table class="table table-zebra"> <thead class="bg-base-200 text-base"> <tr> <th>Sl</th> <th>Product Name</th> <th>Order Qty</th> <th>Warehouse</th> <th>Production Need</th> </tr> </thead> <tbody>'; $sl = $from; if ($result && mysqli_num_rows($result) > 0) { $firstRow = mysqli_fetch_assoc($result); $warehouse = $firstRow['delivery_point_name']; $htmlTableHead = '<div class="text-3xl text-center">' . $firstRow['project_name'] . '</div> <div class="text-center"> <span class="text-primary">' . $firstRow['location'] . '</span> </div>'; mysqli_data_seek($result, 0); while ($row = mysqli_fetch_assoc($result)) { $sl++; $stockQty = getStockBalanceQty($row["project_id"], $row["productID"], $row["store_id"], $date_to); $productionNeed = $row["order_qty"] - $stockQty; $productName = !empty($row["product_name"]) ? htmlspecialchars_decode($row["product_name"]) : htmlspecialchars_decode($row["details"]); $stocks[] = [ "sl" => $sl, "date" => $row["sales_date"], "invoice" => $row["invoice"], "party_name" => $row["party_name"], "order_qty" => $row["order_qty"] ]; $htmlContent .= '<tr> <th>' . $sl . '</th> <th><div class="cursor-pointer" onclick=showDetail("' . $row["productID"] . '")>' . $productName . '</div></th> <td>' . $row["order_qty"] . '</td> <td>' . number_format($stockQty, 2) . ' ' . $row["m_unit"] . '<br/>(' . $row["delivery_point_name"] . ')</td> <td>' . number_format($productionNeed, 2) . ' ' . $row["m_unit"] . '</td> </tr>'; } } else { $htmlContent .= '<tr><td colspan="5" class="text-center">No record found</td></tr>'; } $htmlContent .= '</tbody></table>'; $data = [ "status" => true, "data" => [ "html" => $htmlContent, "pagination" => $Pagination, "tableHead" => $htmlTableHead, "stocks" => $stocks ] ]; echo json_encode($data); exit; } if ($_POST['action'] === 'get_product_details') { $perPage = 10; $from = isset($_POST['from']) ? intval($_POST['from']) : 0; $to = isset($_POST['to']) ? intval($_POST['to']) : $perPage; $date_from = isset($_POST['date_from']) ? $_POST['date_from'] : ""; $date_to = isset($_POST['date_to']) ? $_POST['date_to'] : ""; $product_id = isset($_POST['product_id']) ? $_POST['product_id'] : ""; if ($from == "") { $from = 0; } if ($to == "") { $to = $perPage; } if ($product_id == "") { echo json_encode(["status" => false, "message" => "Product ID missing!"]); exit; } if ($date_from != "") { $date_from = formatDateDMY($date_from); } if ($date_to != "") { $date_to = formatDateDMY($date_to); } $sql = "SELECT sm.sales_date as order_date, sd.voucher_no as invoice, SUM(sd.qty + sd.free_qty) as order_qty, po.m_unit, c.sub_head_name as party_name FROM sales_details AS sd LEFT JOIN sales_master AS sm ON sm.voucher_no = sd.voucher_no LEFT JOIN product AS po ON sd.product = po.product_id LEFT JOIN sub_acc_head AS c ON sm.customer = c.sub_id WHERE sd.product = '$product_id' AND sd.delivery_qty = 0 AND sm.status = 1"; if ($date_from != "" && $date_to == "") { $sql .= " AND sm.sales_date >= '$date_from'"; } elseif ($date_from == "" && $date_to != "") { $sql .= " AND sm.sales_date <= '$date_to'"; } elseif ($date_from != "" && $date_to != "") { $sql .= " AND sm.sales_date BETWEEN '$date_from' AND '$date_to'"; } $sql .= " GROUP BY sd.voucher_no, sd.product"; $totalResult = getData($sql); $totalRecord = mysqli_num_rows($totalResult); $sql .= " ORDER BY sd.voucher_no DESC LIMIT $from, $to"; $result = getData($sql); $pagination = ""; if ($totalRecord > 0) { $pagination = ellipsisPagination($totalRecord, $perPage, "nextPageSec"); } $sl = $from; $html = '<table class="table table-zebra"> <thead class="bg-base-200 text-base"> <tr> <th>SL.</th> <th>Order Date</th> <th>Invoice</th> <th>Part Name</th> <th>Order Qty</th> </tr> </thead> <tbody>'; if ($result && mysqli_num_rows($result) > 0) { while ($row = mysqli_fetch_assoc($result)) { $sl++; $html .= '<tr> <th>' . $sl . '</th> <td>' . $row["order_date"] . '</td> <td>' . $row["invoice"] . '</td> <td>' . $row["party_name"] . '</td> <td>' . number_format($row["order_qty"], 2, '.', '') . ' ' . $row["m_unit"] . '</td> </tr>'; } } else { $html .= '<tr><td colspan="5" class="text-center">No record found</td></tr>'; } $html .= '</tbody></table>'; echo json_encode([ "status" => true, "data" => [ "html" => $html, "pagination" => $pagination ] ]); exit; } }
?>

